module top_module(
  input  clk_i,
  input  en_i,
  input  test_en_i,
  output clk_o
);reg en_latch;

  always @* begin
    if (!clk_i) begin
      en_latch = en_i | test_en_i;
    end
  end
  wire temp1_en_latch = en_latch;
  wire temp2_clk_i = clk_i;
  assign clk_o = temp1_en_latch & temp2_clk_i;

endmodule
